                                             const T,
                                             const T&>;
 
+    template <typename T>
+    struct is_shared_ptr : std::false_type {};
+
+    template <typename T>
+    struct is_shared_ptr<std::shared_ptr<T>> : std::true_type {};
+
 } // namespace details
 
 //
